{
  "id": "backups-001-setup-backup-schedule",
  "title": "Set Up Backup Schedule on Mittwald",
  "description": "Configure automated backup schedule on Mittwald hosting.",
  "domain": "backups",
  "prompt": "I need to check my backup configuration on Mittwald. Use the Mittwald MCP tools to list my projects and their existing backup schedules.",
  "expectedDomains": ["backups", "project-foundation"],
  "expectedTools": [
    "mcp__mittwald__mittwald_project_list",
    "mcp__mittwald__mittwald_backup_schedule_list"
  ],
  "successCriteria": [
    {
      "description": "Backup or project tools used",
      "method": "log-pattern",
      "config": {
        "pattern": "mcp__mittwald__mittwald_(backup|project)",
        "minOccurrences": 1
      }
    }
  ],
  "cleanupRequirements": [],
  "questionAnswers": [
    { "questionPattern": "which project", "answer": "The main production project" }
  ],
  "estimatedDuration": 4,
  "timeout": 12,
  "priority": "P1",
  "tags": ["backups", "schedule", "mittwald"]
}
